// Extract document info from Paperless-ngx webhook payload
const body = $input.first().json.body || $input.first().json;

const docId = body.document_id || body.id || '';
const title = body.title || body.document_title || '';
const correspondent = body.correspondent_name || body.correspondent || '';
const tags = body.tags || body.tag_names || [];
const tagNames = Array.isArray(tags) ? tags.map(t => typeof t === 'string' ? t : t.name || '') : [];
const createdDate = body.created || body.created_date || new Date().toISOString();
const content = body.content || '';

// Try to extract entity number from document content (pattern: 7-digit number)
const entityNumberMatch = content.match(/\b(\d{7})\b/);
const entityNumber = entityNumberMatch ? entityNumberMatch[1] : '';

// Classify document type from tags or content
let docType = 'general';
const contentLower = content.toLowerCase();
if (tagNames.some(t => t.toLowerCase().includes('service of process')) || contentLower.includes('summons') || contentLower.includes('complaint') || contentLower.includes('subpoena')) {
  docType = 'service_of_process';
} else if (contentLower.includes('annual report') || contentLower.includes('annual filing')) {
  docType = 'annual_report_notice';
} else if (tagNames.some(t => t.toLowerCase().includes('government')) || contentLower.includes('department of state') || contentLower.includes('bureau of corporations')) {
  docType = 'government_correspondence';
} else if (contentLower.includes('tax') || contentLower.includes('revenue')) {
  docType = 'tax_notice';
}

// Determine urgency
let urgency = 'normal';
if (docType === 'service_of_process') urgency = 'critical';
else if (docType === 'annual_report_notice') urgency = 'high';

return [{
  json: {
    paperlessDocId: docId,
    title,
    correspondent,
    tags: tagNames,
    docType,
    urgency,
    entityNumber,
    createdDate,
    contentPreview: content.substring(0, 500),
    paperlessUrl: `${process.env.PAPERLESS_URL || 'http://localhost:8000'}/documents/${docId}/preview/`
  }
}];

const docInfo = $('Extract Document Info').first().json;
const clientResult = $input.first().json;
const records = clientResult.data?.records || [];

let clientFound = false;
let clientEmail = '';
let clientName = '';
let suitedashContactId = '';

if (records.length > 0) {
  const client = records[0].fields;
  clientEmail = client.Email || '';
  clientName = client.Name || '';
  suitedashContactId = client['SuiteDash ID'] || '';
  clientFound = true;
}

// Build notification email based on doc type
let subject = '';
let body = '';

switch (docInfo.docType) {
  case 'service_of_process':
    subject = `🚨 URGENT: Legal document received for ${docInfo.correspondent || 'your entity'}`;
    body = `<p>Hi ${clientName || 'there'},</p><p><strong>We received a legal document (service of process) for your entity today.</strong> This requires your immediate attention.</p><p>The document has been scanned and is available in your client portal. Please log in to review it or contact your attorney.</p><p><strong>Document type:</strong> Service of Process<br><strong>Date received:</strong> ${new Date(docInfo.createdDate).toLocaleDateString()}</p><p>If you need assistance, contact us immediately at hello@pacropservices.com or call 814-480-0989.</p>`;
    break;
  case 'annual_report_notice':
    subject = `Annual report notice received for ${docInfo.correspondent || 'your entity'}`;
    body = `<p>Hi ${clientName || 'there'},</p><p>We received an annual report notice from the PA Department of State for your entity. The notice has been scanned and uploaded to your portal.</p><p>Remember: filing on time avoids the dissolution penalties starting in 2027. If you'd like us to handle the filing for you, just reply to this email.</p>`;
    break;
  default:
    subject = `New document received for ${docInfo.correspondent || 'your entity'}`;
    body = `<p>Hi ${clientName || 'there'},</p><p>We received a document for your entity and have scanned and uploaded it to your client portal.</p><p><strong>Document:</strong> ${docInfo.title}<br><strong>Date received:</strong> ${new Date(docInfo.createdDate).toLocaleDateString()}</p><p>Log in to your portal to view it.</p>`;
}

body += `<p style="margin-top:24px;color:#6B7280;font-size:13px">— PA CROP Services<br>hello@pacropservices.com</p>`;

return [{
  json: {
    ...docInfo,
    clientFound,
    clientEmail,
    clientName,
    suitedashContactId,
    emailSubject: subject,
    emailBody: body
  }
}];
